import React, { useState, useEffect, useCallback, useRef } from 'react';
import {
  BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer,
  RadarChart, Radar, PolarGrid, PolarAngleAxis, PolarRadiusAxis,
} from 'recharts';

// ── API ────────────────────────────────────────────────────────────────────────
const API = 'http://localhost:8000';

async function fetchRecommend(userId, nCandidates = 200, nResults = 10) {
  const r = await fetch(`${API}/recommend`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ user_id: userId, n_candidates: nCandidates, n_results: nResults }),
  });
  if (!r.ok) throw new Error(`API error ${r.status}`);
  return r.json();
}

async function fetchUser(userId) {
  const r = await fetch(`${API}/user/${userId}`);
  if (!r.ok) throw new Error(`User not found`);
  return r.json();
}

async function fetchMetrics() {
  const r = await fetch(`${API}/metrics`);
  if (!r.ok) throw new Error('Metrics unavailable');
  return r.json();
}

async function fetchHealth() {
  const r = await fetch(`${API}/health`);
  return r.json();
}

// ── Utilities ──────────────────────────────────────────────────────────────────
const GENRE_COLORS = {
  Action: '#ef4444', Comedy: '#f59e0b', Drama: '#8b5cf6',
  'Sci-Fi': '#06b6d4', Thriller: '#f97316', Romance: '#ec4899',
  Horror: '#dc2626', Animation: '#10b981', Documentary: '#6366f1',
  Fantasy: '#a855f7', Crime: '#64748b', Adventure: '#14b8a6',
};

function genreColor(g) { return GENRE_COLORS[g] || '#94a3b8'; }
function starStr(r) { return '★'.repeat(Math.round(r)) + '☆'.repeat(5 - Math.round(r)); }

