// ── Components ────────────────────────────────────────────────────────────────

function SkeletonCard() {
  return (
    <div className="skeleton-card">
      <div className="skeleton" style={{ height: 14, width: '60%' }} />
      <div className="skeleton" style={{ height: 10, width: '35%' }} />
      <div style={{ display: 'flex', gap: 4 }}>
        <div className="skeleton" style={{ height: 18, width: 56, borderRadius: 100 }} />
        <div className="skeleton" style={{ height: 18, width: 48, borderRadius: 100 }} />
      </div>
      <div className="skeleton" style={{ height: 54 }} />
    </div>
  );
}

function ResultCard({ item, maxScore }) {
  const s2norm = Math.max(0, Math.min(1, item.stage2_score / (maxScore || 1)));
  const s1norm = Math.max(0, Math.min(1, item.stage1_score));

  return (
    <div className="result-card">
      <div className="card-rank">#{item.rank}</div>
      <div>
        <div className="card-title">{item.title}</div>
        <div className="card-year">{item.year}</div>
      </div>

      <div className="card-genres">
        {item.genres.slice(0, 3).map(g => (
          <span key={g} className="card-genre" style={{
            backgroundColor: genreColor(g) + '18',
            color: genreColor(g),
            border: `1px solid ${genreColor(g)}44`,
          }}>{g}</span>
        ))}
      </div>

      <div className="card-scores">
        <div className="score-box">
          <div className="score-label">Stage 2 Score</div>
          <div className="score-val">{item.stage2_score.toFixed(3)}</div>
          <div className="score-bar">
            <div className="score-bar-fill" style={{ width: `${s2norm * 100}%` }} />
          </div>
        </div>
        <div className="score-box">
          <div className="score-label">Stage 1 Score</div>
          <div className="score-val">{item.stage1_score.toFixed(3)}</div>
          <div className="score-bar">
            <div className="score-bar-fill" style={{ width: `${s1norm * 100}%`, background: 'linear-gradient(90deg, var(--cyan), #a78bfa)' }} />
          </div>
        </div>
      </div>

      <div className="card-rating">
        <span>{starStr(item.avg_rating)}</span>
        <span style={{ color: 'var(--text-muted)' }}>{item.avg_rating.toFixed(1)}</span>
        <span style={{ color: 'var(--text-dim)', fontSize: 10 }}>avg</span>
      </div>
    </div>
  );
}

function PipelineViz({ pipeline, totalLatency }) {
  if (!pipeline?.length) return null;

  const TOTAL_ITEMS = pipeline[0]?.n_items_in || 500000;

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
      <div className="pipeline">
        <div className="pipeline-stage" style={{ maxWidth: 140 }}>
          <div className="stage-num">INPUT</div>
          <div className="stage-name">All Items</div>
          <div className="stage-method">Item catalog</div>
          <div className="stage-stats">
            <div className="stage-stat">
              <div className="stage-stat-val amber">{TOTAL_ITEMS.toLocaleString()}</div>
              <div className="stage-stat-label">total items</div>
            </div>
          </div>
        </div>

        {pipeline.map((stage, i) => (
          <React.Fragment key={i}>
            <div className="arrow">→</div>
            <div className="pipeline-stage">
              <div className="stage-num">STAGE {i + 1}</div>
              <div className="stage-name">{i === 0 ? 'Candidate Gen' : 'Ranking'}</div>
              <div className="stage-method" style={{ fontSize: 10 }}>
                {i === 0 ? 'ALS + FAISS ANN' : 'LightGBM LambdaMART'}
              </div>
              <div className="stage-stats">
                <div className="stage-stat">
                  <div className={`stage-stat-val ${i === 0 ? 'green' : ''}`} style={i === 1 ? { color: 'var(--accent-2)' } : {}}>
                    {stage.n_items_out}
                  </div>
                  <div className="stage-stat-label">items out</div>
                </div>
                <div className="stage-stat">
                  <div className="stage-stat-val" style={{ fontSize: 14, color: 'var(--cyan)' }}>
                    {stage.latency_ms}ms
                  </div>
                  <div className="stage-stat-label">latency</div>
                </div>
              </div>
            </div>
          </React.Fragment>
        ))}

        <div className="arrow">→</div>
        <div className="pipeline-stage" style={{ maxWidth: 120 }}>
          <div className="stage-num">OUTPUT</div>
          <div className="stage-name">Results</div>
          <div className="stage-method">Served to user</div>
          <div className="stage-stats">
            <div className="stage-stat">
              <div className="stage-stat-val" style={{ color: 'var(--green)' }}>{totalLatency}ms</div>
              <div className="stage-stat-label">total</div>
            </div>
          </div>
        </div>
      </div>

      <div style={{ fontSize: 11, color: 'var(--text-dim)', fontFamily: 'var(--mono)', textAlign: 'right' }}>
        funnel: {TOTAL_ITEMS.toLocaleString()} → {pipeline[0]?.n_items_out} → {pipeline[1]?.n_items_out ?? '—'} items
      </div>
    </div>
  );
}

function RecommendTab({ recs, loading, coldStart }) {
  if (loading) {
    return (
      <div className="results-grid">
        {Array.from({ length: 10 }).map((_, i) => <SkeletonCard key={i} />)}
      </div>
    );
  }

  if (!recs) {
    return (
      <div className="empty-state">
        <div className="empty-icon">🎬</div>
        <div className="empty-title">Run your first recommendation</div>
        <div className="empty-desc">
          Enter a user ID and click <strong>Get Recommendations</strong> to see the two-stage pipeline in action.
        </div>
      </div>
    );
  }

  const maxScore = Math.max(...recs.results.map(r => r.stage2_score), 0.001);

  return (
    <>
      {coldStart && (
        <div className="cold-start-banner">
          ⚠ Cold start — no embedding found for this user. Falling back to popularity-based candidates.
        </div>
      )}
      <div className="results-grid">
        {recs.results.map(item => (
          <ResultCard key={item.item_id} item={item} maxScore={maxScore} />
        ))}
      </div>
    </>
  );
}

function MetricsTab({ metrics }) {
  if (!metrics) {
    return (
      <div className="empty-state">
        <div className="empty-icon">📊</div>
        <div className="empty-title">No metrics yet</div>
        <div className="empty-desc">Metrics will appear after the models are trained and the server is running.</div>
      </div>
    );
  }

  const { system, stage1, stage2, data, stage2_feature_importance } = metrics;

  const featureData = Object.entries(stage2_feature_importance || {})
    .map(([name, val]) => ({ name: name.replace(/_/g, ' '), value: Math.round(val) }))
    .sort((a, b) => b.value - a.value)
    .slice(0, 10);

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 24 }}>
      <div className="metrics-section">
        <div className="metrics-section-title">Live System</div>
        <div className="metrics-grid">
          {[
            { label: 'Requests', val: system.request_count, sub: 'total served' },
            { label: 'p50 Latency', val: `${system.p50_latency_ms?.toFixed(0)}ms`, sub: 'median' },
            { label: 'p95 Latency', val: `${system.p95_latency_ms?.toFixed(0)}ms`, sub: '95th percentile' },
            { label: 'p99 Latency', val: `${system.p99_latency_ms?.toFixed(0)}ms`, sub: '99th percentile' },
          ].map(m => (
            <div key={m.label} className="metric-card">
              <div className="metric-label">{m.label}</div>
              <div className="metric-val" style={{ fontSize: 22 }}>{m.val}</div>
              <div className="metric-sub">{m.sub}</div>
            </div>
          ))}
        </div>
      </div>

      <div className="metrics-section">
        <div className="metrics-section-title">Offline Evaluation</div>
        <div className="metrics-grid">
          {[
            { label: 'Recall@200', val: stage1.recall_at_200 != null ? (stage1.recall_at_200 * 100).toFixed(1) + '%' : '—', sub: 'Stage 1 candidate quality' },
            { label: 'NDCG@10', val: stage2.ndcg_at_10 != null ? stage2.ndcg_at_10.toFixed(3) : '—', sub: 'Stage 2 ranking quality' },
            { label: 'ALS Factors', val: stage1.n_factors ?? '—', sub: 'embedding dimensions' },
            { label: 'Train Interactions', val: stage1.n_interactions?.toLocaleString() ?? '—', sub: 'implicit feedback rows' },
          ].map(m => (
            <div key={m.label} className="metric-card">
              <div className="metric-label">{m.label}</div>
              <div className="metric-val" style={{ fontSize: 22 }}>{m.val}</div>
              <div className="metric-sub">{m.sub}</div>
            </div>
          ))}
        </div>
      </div>

      <div className="metrics-section">
        <div className="metrics-section-title">Data</div>
        <div className="metrics-grid">
          {[
            { label: 'Users', val: data.n_users?.toLocaleString() ?? '—', sub: 'unique users' },
            { label: 'Items', val: data.n_items?.toLocaleString() ?? '—', sub: 'in catalog' },
            { label: 'Interactions', val: data.n_interactions?.toLocaleString() ?? '—', sub: 'implicit feedback events' },
          ].map(m => (
            <div key={m.label} className="metric-card">
              <div className="metric-label">{m.label}</div>
              <div className="metric-val" style={{ fontSize: 22 }}>{m.val}</div>
              <div className="metric-sub">{m.sub}</div>
            </div>
          ))}
        </div>
      </div>

      {featureData.length > 0 && (
        <div className="chart-wrap">
          <div className="chart-title">Feature Importance — LightGBM LambdaMART</div>
          <ResponsiveContainer width="100%" height={240}>
            <BarChart data={featureData} layout="vertical" margin={{ left: 100, right: 20 }}>
              <XAxis type="number" tick={{ fill: '#6e6e8a', fontSize: 10, fontFamily: 'JetBrains Mono' }} />
              <YAxis type="category" dataKey="name" tick={{ fill: '#9898b8', fontSize: 11, fontFamily: 'JetBrains Mono' }} width={100} />
              <Tooltip
                contentStyle={{ background: '#16161f', border: '1px solid #252535', borderRadius: 8, fontFamily: 'JetBrains Mono', fontSize: 12 }}
                labelStyle={{ color: '#e8e8f0' }}
                itemStyle={{ color: '#a78bfa' }}
              />
              <Bar dataKey="value" fill="url(#barGrad)" radius={[0, 4, 4, 0]} />
              <defs>
                <linearGradient id="barGrad" x1="0" x2="1" y1="0" y2="0">
                  <stop offset="0%" stopColor="#7c6aff" />
                  <stop offset="100%" stopColor="#22d3ee" />
                </linearGradient>
              </defs>
            </BarChart>
          </ResponsiveContainer>
        </div>
      )}
    </div>
  );
}

function ArchitectureTab() {
  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
      <div className="arch-diagram">
        <div><span className="arch-highlight">TWO-STAGE RECOMMENDER ARCHITECTURE</span></div>
        <div style={{ marginTop: 8 }}>
          <span className="arch-amber">INPUT</span>  → user_id
        </div>
        <div style={{ marginTop: 16 }}>
          <span className="arch-highlight">╔══════════════════════════════════════════╗</span>
        </div>
        <div><span className="arch-highlight">║  STAGE 1 — CANDIDATE GENERATION         ║</span></div>
        <div><span className="arch-highlight">║</span>  Model: Alternating Least Squares (ALS)  <span className="arch-highlight">║</span></div>
        <div><span className="arch-highlight">║</span>  Loss:  Implicit confidence (1 + αr)     <span className="arch-highlight">║</span></div>
        <div><span className="arch-highlight">║</span>  Index: <span className="arch-cyan">FAISS IndexFlatIP</span> (64-dim)       <span className="arch-highlight">║</span></div>
        <div><span className="arch-highlight">║</span>  Output: top-200 candidate items          <span className="arch-highlight">║</span></div>
        <div><span className="arch-highlight">║</span>  Eval:  <span className="arch-green">Recall@200</span>                       <span className="arch-highlight">║</span></div>
        <div><span className="arch-highlight">╚══════════════════════════════════════════╝</span></div>
        <div style={{ textAlign: 'center' }}>↓ <span style={{ color: 'var(--text-dim)' }}>200 candidates</span></div>
        <div>
          <span className="arch-highlight">╔══════════════════════════════════════════╗</span>
        </div>
        <div><span className="arch-highlight">║  STAGE 2 — RANKING                      ║</span></div>
        <div><span className="arch-highlight">║</span>  Model: <span className="arch-cyan">LightGBM LambdaMART</span>             <span className="arch-highlight">║</span></div>
        <div><span className="arch-highlight">║</span>  Loss:  Listwise NDCG optimization       <span className="arch-highlight">║</span></div>
        <div><span className="arch-highlight">║</span>  Features: stage1_score, popularity,     <span className="arch-highlight">║</span></div>
        <div><span className="arch-highlight">║</span>            avg_rating, user_history,     <span className="arch-highlight">║</span></div>
        <div><span className="arch-highlight">║</span>            embedding norms, recency       <span className="arch-highlight">║</span></div>
        <div><span className="arch-highlight">║</span>  Split:  <span className="arch-amber">Temporal</span> (no future leakage)    <span className="arch-highlight">║</span></div>
        <div><span className="arch-highlight">║</span>  Eval:  <span className="arch-green">NDCG@10, MAP</span>                    <span className="arch-highlight">║</span></div>
        <div><span className="arch-highlight">╚══════════════════════════════════════════╝</span></div>
        <div style={{ textAlign: 'center' }}>↓ <span style={{ color: 'var(--text-dim)' }}>top-10 ranked</span></div>
        <div><span className="arch-amber">OUTPUT</span> → POST /recommend → ranked item list</div>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12 }}>
        {[
          {
            title: 'Why Two Stages?',
            text: "Running a heavy ranking model over millions of items is infeasible in real time. Stage 1 cheaply narrows the space (milliseconds, cosine lookup). Stage 2 then applies expensive features only to a few hundred candidates. This is the exact pattern used by YouTube, Amazon, and Meta at scale.",
          },
          {
            title: 'Cold Start Strategy',
            text: "New users have no embedding. The system falls back to popularity-based candidates (Pareto-distributed item frequencies). In production you'd combine content-based features and onboarding signals.",
          },
          {
            title: 'Temporal Split',
            text: "Train on past interactions, test on future ones. Random splitting leaks future signal and gives falsely optimistic metrics. Temporal split mirrors real deployment conditions.",
          },
          {
            title: 'LambdaMART vs Classification',
            text: "Framing ranking as binary classification ignores the relative ordering of items. LambdaMART directly optimizes NDCG — the metric that actually matters — via pairwise gradient computation.",
          },
        ].map(card => (
          <div key={card.title} className="metric-card">
            <div style={{ fontFamily: 'var(--display)', fontWeight: 600, marginBottom: 6 }}>{card.title}</div>
            <div style={{ fontSize: 12, color: 'var(--text-muted)', lineHeight: 1.6 }}>{card.text}</div>
          </div>
        ))}
      </div>
    </div>
  );
}

function HistoryTab({ userProfile }) {
  if (!userProfile) {
    return (
      <div className="empty-state">
        <div className="empty-icon">🕐</div>
        <div className="empty-title">No user loaded</div>
        <div className="empty-desc">Load a user to see their interaction history.</div>
      </div>
    );
  }

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
      <div className="metrics-section-title">Recent interactions for user #{userProfile.user_id}</div>
      <div className="history-list">
        {userProfile.recent_history?.map(item => (
          <div key={item.item_id} className="history-item">
            <div className="history-rating">{item.rating.toFixed(1)}★</div>
            <div className="history-title">{item.title}</div>
            <div className="history-genres">
              {item.genres.slice(0, 3).map(g => (
                <div key={g} className="history-genre-dot" style={{ background: genreColor(g) }} title={g} />
              ))}
            </div>
          </div>
        ))}
        {!userProfile.recent_history?.length && (
          <div style={{ color: 'var(--text-muted)', fontSize: 13, padding: '12px 0' }}>No interaction history found.</div>
        )}
      </div>
    </div>
  );
}

// ── App ───────────────────────────────────────────────────────────────────────

export default function App() {
  const [userId, setUserId] = useState(42);
  const [nCandidates, setNCandidates] = useState(200);
  const [nResults, setNResults] = useState(10);
  const [loading, setLoading] = useState(false);
  const [recs, setRecs] = useState(null);
  const [userProfile, setUserProfile] = useState(null);
  const [metrics, setMetrics] = useState(null);
  const [health, setHealth] = useState(null);
  const [activeTab, setActiveTab] = useState('recommendations');
  const [error, setError] = useState(null);

  // Poll health
  useEffect(() => {
    const poll = async () => {
      try { setHealth(await fetchHealth()); } catch {}
    };
    poll();
    const id = setInterval(poll, 5000);
    return () => clearInterval(id);
  }, []);

  // Load metrics
  useEffect(() => {
    if (activeTab === 'metrics') {
      fetchMetrics().then(setMetrics).catch(() => {});
    }
  }, [activeTab]);

  const handleRecommend = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const [recsData, profileData] = await Promise.all([
        fetchRecommend(userId, nCandidates, nResults),
        fetchUser(userId).catch(() => null),
      ]);
      setRecs(recsData);
      setUserProfile(profileData);
      setActiveTab('recommendations');
    } catch (e) {
      setError(e.message);
    } finally {
      setLoading(false);
    }
  }, [userId, nCandidates, nResults]);

  const isOnline = health?.status === 'ok';
  const modelsReady = health?.stage1_loaded && health?.stage2_loaded;

  const TABS = [
    { id: 'recommendations', label: 'Recommendations', count: recs?.results?.length },
    { id: 'history', label: 'User History' },
    { id: 'metrics', label: 'Metrics' },
    { id: 'architecture', label: 'Architecture' },
  ];

  return (
    <>
      <style>{styles}</style>
      <div className="app">

        {/* Header */}
        <header className="header">
          <div className="header-logo">
            <div className="logo-dot">⚡</div>
            RecSys
          </div>
          <span className="header-badge">TWO-STAGE</span>
          <div className="header-status">
            <div className={`status-dot ${isOnline ? '' : 'offline'}`} />
            <span className="status-label">
              {isOnline
                ? modelsReady ? 'Models ready' : 'Server up, run train.py'
                : 'Server offline — start uvicorn'}
            </span>
          </div>
        </header>

        {/* Sidebar */}
        <aside className="sidebar">
          <div>
            <div className="sidebar-section-label">Configure</div>
            <div className="user-input-group">
              <div className="input-label">User ID</div>
              <input
                type="number"
                value={userId}
                min={0}
                max={1999}
                onChange={e => setUserId(Number(e.target.value))}
                placeholder="0–1999"
              />

              <div className="input-label" style={{ marginTop: 4 }}>Candidates (Stage 1)</div>
              <div className="range-row">
                <input type="range" min={50} max={500} step={50} value={nCandidates}
                  onChange={e => setNCandidates(Number(e.target.value))} />
                <span className="range-val">{nCandidates}</span>
              </div>

              <div className="input-label">Results (Stage 2)</div>
              <div className="range-row">
                <input type="range" min={5} max={20} step={1} value={nResults}
                  onChange={e => setNResults(Number(e.target.value))} />
                <span className="range-val">{nResults}</span>
              </div>

              <button className="btn" onClick={handleRecommend} disabled={loading || !isOnline}>
                {loading ? 'Running pipeline…' : 'Get Recommendations'}
              </button>

              {error && (
                <div style={{ fontSize: 11, color: 'var(--red)', background: 'rgba(239,68,68,0.08)', border: '1px solid rgba(239,68,68,0.2)', borderRadius: 6, padding: '8px 10px' }}>
                  ⚠ {error}
                </div>
              )}
            </div>
          </div>

          {userProfile && (
            <div>
              <div className="sidebar-section-label">User Profile</div>
              <div className="user-card">
                <div className="user-card-header">
                  <div className="avatar">U{userProfile.user_id % 99}</div>
                  <div>
                    <div className="user-name">User #{userProfile.user_id}</div>
                    <div className="user-meta">{userProfile.has_embedding ? '✓ has embedding' : '⚠ cold start'}</div>
                  </div>
                </div>

                <div className="genre-chips">
                  {userProfile.top_genres?.map(g => (
                    <span key={g} className="genre-chip" style={{
                      color: genreColor(g),
                      backgroundColor: genreColor(g) + '18',
                      borderColor: genreColor(g) + '44',
                    }}>{g}</span>
                  ))}
                </div>

                <div className="user-stat-row">
                  <div className="user-stat">
                    <div className="user-stat-val">{userProfile.n_ratings}</div>
                    <div className="user-stat-label">ratings</div>
                  </div>
                  <div className="user-stat">
                    <div className="user-stat-val">{userProfile.joined_days_ago}d</div>
                    <div className="user-stat-label">member</div>
                  </div>
                </div>
              </div>
            </div>
          )}

          {recs && (
            <div>
              <div className="sidebar-section-label">Last Request</div>
              <div className="user-card">
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 6 }}>
                  <div className="user-stat">
                    <div className="user-stat-val" style={{ fontSize: 14 }}>{recs.total_latency_ms}ms</div>
                    <div className="user-stat-label">total latency</div>
                  </div>
                  <div className="user-stat">
                    <div className="user-stat-val" style={{ fontSize: 14 }}>{recs.pipeline?.[0]?.n_items_out}</div>
                    <div className="user-stat-label">candidates</div>
                  </div>
                </div>
              </div>
            </div>
          )}
        </aside>

        {/* Main */}
        <main className="main">
          <div className="main-tabs">
            {TABS.map(tab => (
              <div key={tab.id} className={`tab ${activeTab === tab.id ? 'active' : ''}`}
                onClick={() => setActiveTab(tab.id)}>
                {tab.label}
                {tab.count != null && <span className="tab-count">{tab.count}</span>}
              </div>
            ))}
          </div>

          <div className="content">
            {/* Pipeline always shown when there are recs */}
            {recs && activeTab === 'recommendations' && (
              <PipelineViz pipeline={recs.pipeline} totalLatency={recs.total_latency_ms} />
            )}

            {activeTab === 'recommendations' && (
              <RecommendTab recs={recs} loading={loading} coldStart={recs?.cold_start} />
            )}
            {activeTab === 'history' && <HistoryTab userProfile={userProfile} />}
            {activeTab === 'metrics' && <MetricsTab metrics={metrics} />}
            {activeTab === 'architecture' && <ArchitectureTab />}
          </div>
        </main>
      </div>
    </>
  );
}
